async function safeInvoke<T>(command: string, args?: Record<string, unknown>): Promise<T> {
  try {
    const tauriCore = await import('@tauri-apps/api/core');
    return await tauriCore.invoke<T>(command, args);
  } catch (error) {
    throw error;
  }
}

export async function loadBackendCatalog(): Promise<BackendCatalog> {
  try {
    return await safeInvoke<BackendCatalog>('get_backend_integration_catalog');
  } catch {
    return browserFallbackCatalog;
  }
}

