export async function compressToolkitPayload(payload: string): Promise<string> {
  return safeInvoke<string>('compress_text_lzma', { payload });
}

export async function decompressToolkitPayload(payloadBase64: string): Promise<string> {
  return safeInvoke<string>('decompress_text_lzma', { payloadBase64 });
}

export async function encryptToolkitPayload(payload: string, passphrase: string): Promise<EncryptedPayload> {
  return safeInvoke<EncryptedPayload>('encrypt_text_payload', { payload, passphrase });
}

export async function decryptToolkitPayload(ciphertextBase64: string, nonceBase64: string, passphrase: string): Promise<string> {
  return safeInvoke<string>('decrypt_text_payload', { ciphertextBase64, nonceBase64, passphrase });
}
